@startuml
skinparam class {
  BackgroundColor White
  BorderColor Black
  FontColor Black
}

skinparam actor {
  BackgroundColor LightGreen
  BorderColor Black
  FontColor Black
}

skinparam association {
  Color Black
}

skinparam extender {
  Color Black
}

skinparam compositeAssociation {
  Color Black
}

skinparam note {
  BackgroundColor White
  BorderColor Black
  FontColor Black
}

class "Client" as Client {
  <<Actor>>
}

class "Target" as Target {
  <<Class>>
  "C"
  targetMethod1 : ??
  targetMethod2 : ??
}

class "Adaptor" as Adaptor {
  <<Class>>
  "C"
  "adaptee: Adaptee"
  targetMethod1() : ??
  targetMethod2() : ??
}

class "Adaptee" as Adaptee {
  <<Class>>
  "C"
  methodA() : ??
  methodB() : ??
  methodC() : ??
}

Client --> Target : uses
Adaptor <|-- Target : extends
Adaptor o-- Adaptee : has

@enduml
